// Laine Industries — validate the website /api/intake payload, normalize the
// form type across contact / short-intake / full-intake, and map it to the
// Factory HQ /api/radar/inbound/website-intake contract. NO SECRETS HERE.

const item = $input.first().json || {};
// The website proxy forwards { formType, submittedAt, summary, source, leadScore,
// leadStatus, data }. n8n wraps the POST body under `.body`; be defensive.
const p = (item.body && typeof item.body === 'object') ? item.body : item;
const data = (p && p.data && typeof p.data === 'object') ? p.data : {};

// Defensive size guard (the website proxy already caps bodies at 64KB).
if (JSON.stringify(p || {}).length > 200000) {
  return [{ json: { valid: false, error: 'invalid_submission', reason: 'payload_too_large' } }];
}

const pick = (...vals) => {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return String(v).trim();
  }
  return null;
};

// Normalize the form type to a stable internal identifier.
const rawType = String(p.formType || '').toLowerCase().trim();
let formType = 'unknown';
if (rawType === 'contact') formType = 'contact';
else if (['intake', 'short-intake', 'short_intake'].includes(rawType)) formType = 'short-intake';
else if (['full-intake', 'full_intake', 'fullintake'].includes(rawType)) formType = 'full-intake';
else if (rawType) formType = rawType;

// business_name is the ONLY hard requirement of the Factory receiver.
const business_name = pick(data.business, data.businessName, data.company);
if (!business_name) {
  return [{ json: { valid: false, error: 'invalid_submission', reason: 'missing_business_name' } }];
}

// Problem, in the submitter's OWN words — combined per form, never fabricated.
let problem = null;
if (formType === 'contact') problem = pick(data.message);
else if (formType === 'short-intake') problem = pick(data.messyThings, data.valuable);
else if (formType === 'full-intake') problem = pick(data.topPriority, data.websiteNotWorking, data.stopDoingManually, data.highestValueOutcome);
if (!problem) problem = pick(p.summary);

// source_page: prefer the first-touch landing path, else the form's canonical route.
const src = (p.source && typeof p.source === 'object') ? p.source : {};
const routeByForm = { 'contact': '/contact', 'short-intake': '/intake', 'full-intake': '/full-intake' };
const landing = pick(src.landing_page);
const source_page = landing
  ? ('https://laineindustries.co' + (landing.startsWith('/') ? landing : '/' + landing))
  : ('https://laineindustries.co' + (routeByForm[formType] || ''));

// message: preserve the full human-readable summary for owner review in
// /ops/first-10 (Factory truncates to 2000 chars; key fields are mapped below).
const message = pick(p.summary, data.message);

// EXACT Factory HQ WebsiteIntakeSubmission shape — only these known fields.
const factoryBody = {
  business_name,
  contact_name: pick(data.name),
  email: pick(data.email),
  phone: pick(data.phone),
  website: pick(data.website),
  niche: pick(data.businessType),                       // contact form has none -> null
  city: pick(data.serviceArea),                         // contact form has none -> null
  problem,
  leads_per_week: pick(data.leadsPerWeek, data.leads_per_week), // no current form asks -> null
  message: message ? message.slice(0, 1900) : null,
  source_page
};

// Internal-only fingerprint for debugging / future dedupe — NOT sent to Factory.
const dedupe_key = [formType, factoryBody.email || '', business_name, pick(p.submittedAt) || ''].join('|');

return [{ json: { valid: true, formType, dedupe_key, factoryBody } }];
